import sqlglot

def validate_sql(sql: str, dialect: str = "sqlite") -> tuple[bool, str]:
    """Parse and validate SQL using sqlglot. Returns (is_valid, error_msg)."""
    try:
        parsed = sqlglot.parse_one(sql, dialect=dialect)
        # Reject any DML that modifies data
        statement_type = type(parsed).__name__
        if statement_type not in ("Select",):
            return False, f"Non-SELECT statement rejected: {statement_type}"
        return True, ""
    except sqlglot.errors.ParseError as e:
        return False, str(e)

def safe_execute(db: SQLDatabase, sql: str) -> str:
    is_valid, error = validate_sql(sql)
    if not is_valid:
        return f"SQL validation failed: {error}"
    try:
        return db.run(sql)
    except Exception as e:
        return f"Execution error: {e}"

