def execute_with_retry(question: str, max_retries: int = 2) -> str:
    sql = generate_query.invoke({"question": question})
    for attempt in range(max_retries + 1):
        is_valid, validation_error = validate_sql(sql)
        if not is_valid:
            error = validation_error
        else:
            try:
                result = db.run(sql)
                # Success — generate natural language answer
                return answer_chain.invoke({
                    "question": question, "query": sql, "result": result
                })
            except Exception as e:
                error = str(e)

        if attempt < max_retries:
            sql = fix_chain.invoke({"question": question, "sql": sql, "error": error})
        else:
            return f"Could not generate a valid SQL query after {max_retries} attempts. Last error: {error}"

